    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Checkbox Automation</title>
</head>
<body>
    <button id="saveButton">Save</button>

    <!-- Example checkboxes -->
    <input type="checkbox" name="option1"> Option 1<br>
    <input type="checkbox" name="option2"> Option 2<br>
    <input type="checkbox" name="option3"> Option 3<br>

    <script>
        // Function to check all checkboxes
        function checkAllCheckboxes() {
            const checkboxes = document.querySelectorAll('input[type="checkbox"]');
            checkboxes.forEach(checkbox => {
                checkbox.checked = true; // Change to false to uncheck them
            });
        }

        // Get the save button element
        const saveButton = document.getElementById('saveButton');

        // Add click event listener to the save button
        saveButton.addEventListener('click', () => {
            checkAllCheckboxes();
            console.log("All checkboxes checked!");
        });
    </script>
</body>
</html>
